const Q_PHYSICS_2025_MODEL_II=[{"id": "objective>Physics>2025 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which condition is necessary for a body to float in equilibrium on a liquid surface?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Upthrust = volume of body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Upthrust > weight of liquid displaced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Weight of body = upthrust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Density of body = volume of liquid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An object floats in equilibrium when its weight equals the upthrust, which means the weight of the displaced liquid equals the weight of the object — exactly what Archimedes' principle dictate.</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>2025 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a thermos flask, which heat transfer method is least affected by the vacuum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Convection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All are equally affected</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A vacuum effectively eliminates conduction and convection because both require a medium (particles or fluid) to transfer heat. However, radiation does not require a medium—it can travel through a vacuum as electromagnetic waves. Therefore, radiation is least affected by the vacuum in a thermos flask, and this is why the flask also includes silvered surfaces to reflect radiation and reduce that form of heat transfer as well.</div>", "topic": "HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>2025 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens when a person with uncorrected hypermetropia tries to read a book?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Image forms behind retina, causing blur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Image forms in front of retina, causing double vision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eye pressure increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eyeball shortens further</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hypermetropia, or farsightedness, occurs when the eye is too short or the cornea has too little curvature. As a result, light rays from nearby objects are focused behind the retina, leading to a blurred image. This makes it difficult to see nearby objects clearly, such as when reading.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2025 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two capacitors C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 6μF and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 3μF are connected in series and charged to 12 V. What is the total energy stored?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.48 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.44 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.48 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.44 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 6μF <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 3μF <br/> V = 12 V <br/>  <br/> For capacitors in series: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 + 2<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span> = 2μF <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span>V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">12<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> E = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 144 <br/>  <br/> ∴ E = 1.44 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> J</div>", "topic": "CAPACITORS : ENERGY STORED IN A CAPACITOR"}, {"id": "objective>Physics>2025 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A charged electroscope has its leaves diverged. A student touches the knob with a finger, and the leaves collapse completely. This demonstrates that:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The student's body is a good insulator.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The student's body has an equal and opposite charge to the electroscope.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The student's body is an electrical ground.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The student's body is a conductor, but not a ground.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the charged electroscope is touched by a student's finger, the leaves collapse. This indicates that charge has left the electroscope, neutralizing it. <br/>  <br/> Here's why this happens: <br/>  <br/> The human body is conductive and connected (ultimately) to the Earth, which is considered an infinite charge reservoir. <br/>  <br/> When the student touches the knob, the excess charge on the electroscope flows to or from the Earth through the student's body, depending on the sign of the charge. <br/>  <br/> This process neutralizes the electroscope. <br/>  <br/> As a result, the leaves no longer repel each other and collapse. <br/>  <br/> Thus, this action demonstrates that the student's body functions as a ground, allowing charge to flow to or from the Earth.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2025 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block of unknown material is found to have an apparent weight of 10 N when fully submerged in water (density 1000 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>) and an apparent weight of 2 N when fully submerged in a different liquid. The block's actual weight is 50 N. What is the density of the second liquid? <br/>  <br/> (Take g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1500 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1200 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">900 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">800 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Actual weight of block = 50 N <br/> Apparent weight in water = 10 N <br/> Apparent weight in unknown liquid = 2 N <br/> Density of water = 1000 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> Upthrust = Actual weight - Apparent weight <br/>  <br/> Upthrust in water = 50 - 10 = 40 N <br/>  <br/> Upthrust = Volume of Object × Density of Fluid × g <br/>  <br/> Upthrust in water = Volume of Object × Density of Water × g <br/>  <br/> 40 = V × 1000 × 10 <br/>  <br/> 40 = 10000V <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />10000</td></tr></table></div> <br/> V = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> Upthrust in second liquid = 50 − 2 = 48 N <br/>  <br/> Upthrust in second liquid = Volume of Object × Density of second liquid × g <br/>  <br/> 48 = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> × ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">liquid</span> × 10 <br/>  <br/> 48 = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">liquid</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">liquid</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">48<hr size=\"1\" />4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> <br/> ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">liquid</span> = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/>  <br/> ∴ Density of the second liquid = 1200 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2025 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a neutron of iron-56 is 1.008665 u and the mass of a proton is 1.007825 u, What is the binding energy per nucleon of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">56</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">26</span>Fe? <br/>  <br/> (Atomic mass of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">56</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">26</span>Fe = 55.934939 u, 1 u = 931.5 MeV/c<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.79 MeV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.65 MeV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.22 MeV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.00 MeV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Z = 26 (number of protons) <br/> A = 56 (mass number = protons + neutrons) <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 1.007825 u <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = 1.008665 u <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">nucleus</span> = 55.934939 u (given as atomic mass; assume electrons' mass is negligible here) <br/>  <br/> Number of neutrons: <br/>  <br/> A - Z = 56 - 26 = 30 <br/>  <br/> Total mass of nucleons if they were free: <br/>  <br/> Mass of 26 protons = 26 × 1.007825 = 26.20345 u  <br/>  <br/> Mass of 30 neutrons = 30 × 1.008665 = 30.25995 u  <br/>  <br/> Total mass of free nucleons = 26.20345 + 30.25995 = 56.4634 u <br/>  <br/> Mass defect: <br/>  <br/> Δm = 56.4634 u − 55.934939 u = 0.528461 u ​ <br/>  <br/> Total binding energy: <br/>  <br/> BE = Δm × 931.5 = 0.528461 × 931.5 = 492.26 MeV <br/>  <br/> Binding energy per nucleon: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">492.26<hr size=\"1\" />56</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8.79</td><td style=\"text-align:center;\">MeV</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}, {"id": "objective>Physics>2025 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is true for overtones in a string?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Overtones are always lower than the fundamental</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All harmonics are present</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only odd harmonics are present</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only even harmonics are present</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a vibrating string fixed at both ends (like a guitar or violin string), the pattern of vibration supports standing waves where both ends are nodes. <br/>  <br/> The fundamental frequency (first harmonic) is the lowest frequency at which the string can vibrate. <br/>  <br/> The overtones are the higher frequencies that are integer multiples of the fundamental. <br/>  <br/> Thus, for strings: <br/>  <br/> The 1st overtone is the 2nd harmonic. <br/>  <br/> The 2nd overtone is the 3rd harmonic, and so on. <br/>  <br/> So, all harmonics (1st, 2nd, 3rd, ...) are present in the vibration pattern of a string fixed at both ends.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : OVERTONES PRODUCED BY VIBRATING STRINGS AND THEIR COLUMNS"}, {"id": "objective>Physics>2025 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal ring is dropped from a certain height and passes through a region of uniform magnetic field. Which of the following statements is true?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The ring's acceleration is greater than g when it is entering the magnetic field.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ring's acceleration is less than g only when it is entering or leaving the magnetic field.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ring's acceleration is less than g while it is completely inside the magnetic field.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ring's acceleration is constant and equal to g.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question explores Lenz's Law and electromagnetic braking. <br/>  <br/> When a conducting ring falls through a magnetic field, a change in magnetic flux through the ring induces eddy currents. According to Lenz's Law, these currents oppose the change that caused them: <br/>  <br/> Entering the field: The increasing magnetic flux induces a current that produces a magnetic field opposing the downward motion — effectively creating an upward force (like a magnetic drag), reducing the acceleration. <br/>  <br/> Fully inside the uniform magnetic field: The flux is constant (no change), so no current is induced, and the ring accelerates at g. <br/>  <br/> Leaving the field: The decreasing flux again induces a current, this time in the opposite direction, but the magnetic drag force still opposes motion, so acceleration < g again.</div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2025 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following correctly describes the energy band structure of an insulator?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Partially filled conduction band and a small energy gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Completely filled valence band and a large energy gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Partially filled valence band and overlapping bands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Completely empty valence band and small energy gap</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An insulator is characterized by a completely filled valence band and a large energy gap between the valence band and the conduction band, which prevents electrons from gaining enough energy to jump to the conduction band under normal conditions, thereby inhibiting electrical conductivity.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2025 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A household has a monthly electricity bill of ₦75. The cost of electricity is ₦0.15 per kilowatt-hour. What is the average power consumption of the household, assuming a 30-day month?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">821.4 W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">783.5 W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">702.6 W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">694.4 W</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Monthly electricity bill = ₦75 <br/> Cost per kWh = ₦0.15 per kWh <br/> Number of days in the month = 30 days <br/>  <br/> 1 day = 24 hours <br/>  <br/> Total hours in 30 days = 30 × 24 = 720 hours <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Energy</td><td style=\"text-align:center;\">(in</td><td style=\"text-align:center;\">kWh)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Total cost<hr size=\"1\" />Cost per kWh</td><td style=\"text-align:center;\">​=</td><td style=\"text-align:center;\">75<hr size=\"1\" />0.15</td><td style=\"text-align:center;\">​=</td><td style=\"text-align:center;\">500</td><td style=\"text-align:center;\">kWh</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Average</td><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Total Energy<hr size=\"1\" />Total Time</td><td style=\"text-align:center;\">​=</td><td style=\"text-align:center;\">500 kWh<hr size=\"1\" />720 hours</td><td style=\"text-align:center;\">​≈</td><td style=\"text-align:center;\">0.6944</td><td style=\"text-align:center;\">kW</td></tr></table></div> <br/> ∴ Average Power = 694.4 W</div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2025 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mercury barometer on the ground floor of a building reads 760 mmHg. An identical barometer on the top floor reads 750 mmHg. If the density of air is 1.2 kg/m³ and the density of mercury is 13600 kg/m³, what is the height of the building? (Assume g = 9.8 m/s²)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">122.5 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">113.3 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">83.7 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">56.2 m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Ground floor pressure (P₁): 760 mmHg <br/> Top floor pressure (P₂): 750 mmHg <br/> Density of air (ρₐᵢᵣ): 1.2 kg/m³ <br/> Density of mercury (ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Hg</span>): 13600 kg/m³ <br/> Acceleration due to gravity (g): 9.8 m/s² <br/>  <br/> Difference in mercury levels: <br/>  <br/> Δh<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Hg</span> = 760 - 750 = 10 mmHg = 0.01 mHg  <br/>  <br/> Pressure difference due to mercury: <br/>  <br/> ΔP = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Hg</span>gh<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Hg</span> = 13600 × 9.8 × 0.01 m <br/>  <br/> ΔP = 1332.8 Pa <br/>  <br/> Using pressure difference to calculate height of the building: <br/>  <br/> ΔP = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">air</span>gh <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔP<hr size=\"1\" />ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">air</span>g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1332.8<hr size=\"1\" />1.2 × 9.8</td></tr></table></div> <br/> ∴ h = 113.3 m</div>", "topic": "PRESSURE: ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2025 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the escape velocity from the surface of a spherical asteroid with a mass of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> kg and a radius of 10 km? <br/>  <br/> (Take G = 6.674 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−11</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.65 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.25 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.85 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00 m/s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Mass M = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span> kg <br/> Radius R = 10 km = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> m <br/> Gravitational constant G = 6.674 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−11</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">2GM<hr size=\"1\" />R</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">2 × 6.674 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−11</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">1.3348 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">1.3348 × 10&nbsp;</span> <br/>  <br/> v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">13.348&nbsp;</span> <br/>  <br/> ∴ v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 3.65 m/s</div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>2025 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer with a coil resistance of 50 Ω gives a full-scale deflection for a current of 10 mA. To convert it into a voltmeter that can read up to 10 V, a high resistance multiplier resistor is connected in series. What is the value of this resistance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">905 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9,905 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">950 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9,950 Ω</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = 50 Ω <br/> I = 10 mA = 1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> A <br/> V = 50 V <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = ? <br/>  <br/> V = IR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> + IR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> <br/>  <br/> V = I(R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>) <br/>  <br/> 10 = 1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>(50 + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>) <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10<hr size=\"1\" />1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td></tr></table></div> <br/> 1000 = 50 + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = 1000 - 50 <br/>  <br/> ∴ R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = 950 Ω</div>", "topic": "MAGNETIC FIELD : CONVERSION OF GALVANOMETERS TO AMMETERS AND VOLTMETER"}, {"id": "objective>Physics>2025 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two capacitors, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20 μF and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 30 μF, are connected in series to an A.C. source of 120 V (RMS) and a frequency of 60 Hz. What is the total capacitive reactance of the circuit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">221 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">352 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">425 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">575 Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20 μF = 20 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> F <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 30 μF = 30 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> F <br/> V = 120 V RMS <br/> f = 60 Hz <br/>  <br/> For capacitors in series: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />20μ</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />30μ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30μ + 20μ<hr size=\"1\" />600μ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50μ<hr size=\"1\" />600μ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">600μ<hr size=\"1\" />50μ</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span> = 12 μF = 12 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> F <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2πfC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2 × π × 60 × 12 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4523.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4523.89</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span></td></tr></table></div> <br/> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span> = 0.000221 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/>  <br/> ∴ X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span> = 221 Ω</div>", "topic": "SIMPLE A. C. CIRCUITS : CAPACITOR - CAPACITIVE REACTANCE"}, {"id": "objective>Physics>2025 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stone is thrown horizontally from the top of a building with an initial speed of 10 m/s. The stone hits the ground at a horizontal distance of 40 m from the base of the building. What is the height of the building? (Take g = 10 m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Initial horizontal velocity, u<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 10 m/s <br/> Horizontal distance (range), x = 40 m <br/> Acceleration due to gravity, g = 10 m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Vertical initial velocity, u<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 0 m/s (thrown horizontally) <br/>  <br/> Finding time of flight (t) from horizontal motion: <br/>  <br/> x = u<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>t <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />u<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />10</td></tr></table></div> <br/> t = 4 seconds <br/>  <br/> Using vertical motion to find height (h): <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>t</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">gt<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0(4)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> h = 0 + 5 × 16 <br/>  <br/> h = 0 + 80 <br/>  <br/> ∴ h = 80 m</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2025 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a sample of germanium is doped with arsenic, what type of semiconductor is formed, and what is the effect on its conductivity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P-type, conductivity increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P-type, conductivity decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N-type, conductivity increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N-type, conductivity decreases</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Germanium (Ge) is a Group IV element and is intrinsic (pure) in its natural state. <br/> Arsenic (As) is a Group V element (pentavalent), meaning it has 5 valence electrons. <br/>  <br/> <strong>When doping occurs:</strong> <br/> One extra electron (the 5th valence electron from arsenic) becomes free to conduct electricity because only 4 electrons are needed to form covalent bonds with neighboring Ge atoms. <br/> This adds free electrons to the semiconductor, making it an N-type semiconductor (N for negative charge carriers - electrons). <br/> The number of free electrons increases, hence conductivity increases.</div>", "topic": "INTRODUCTORY ELECTRONICS : N-TYPE AND P-TYPE SEMI-CONDUCTORS"}, {"id": "objective>Physics>2025 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which scenario violates energy conservation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A pendulum swinging forever without friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A ball rolling uphill without external force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A battery powering a flashlight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solar panels charging during daylight</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is A ball rolling uphill without external force, because it suggests an uncaused gain in potential energy with no input or conversion from another form, which violates the law of conservation of energy, whereas a pendulum swinging forever without friction does not violate the law because, in an idealized frictionless system, mechanical energy is conserved, a battery powering a flashlight transforms stored chemical energy into light and heat, thus conserving total energy, and solar panels charging during daylight convert solar (radiant) energy into electrical energy, which is also a valid energy transformation consistent with conservation principles.</div>", "topic": "WORK ENERGY AND POWER : CONSERVATION OF ENERGY"}, {"id": "objective>Physics>2025 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A convex mirror with a focal length of 10 cm forms an image that is one-third the size of the object. Where is the object located?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> Focal length, f = -10 cm (negative because it's a convex mirror) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Magnification,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span><hr size=\"1\" />h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">u<hr size=\"1\" />3</td><td style=\"text-align:center;\">(negative</td><td style=\"text-align:center;\">because</td><td style=\"text-align:center;\">it's</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">virtual</td><td style=\"text-align:center;\">image)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />-10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />-<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">u</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">3<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 - 3<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">2<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u<hr size=\"1\" />2</td></tr></table></div> <br/> u = 10 × 2 <br/>  <br/> ∴ u = 20 cm in front of the mirror</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2025 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an A.C. generator, the magnetic field is oriented horizontally, and the coil rotates about a horizontal axis. At what position is the induced e.m.f. a maximum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">When the plane of the coil is parallel to the magnetic field lines.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">When the plane of the coil is perpendicular to the magnetic field lines.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">When the magnetic flux through the coil is maximum.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">When the magnetic flux through the coil is zero.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an A.C. generator, the induced e.m.f. is governed by Faraday's Law, which states that the magnitude of the induced e.m.f. is proportional to the rate of change of magnetic flux through the coil. The magnetic flux is maximum when the plane of the coil is perpendicular to the magnetic field lines (i.e., when the coil faces the field head-on), but the rate of change of flux (and thus the induced e.m.f.) is zero at that point. Conversely, the induced e.m.f. is maximum when the plane of the coil is parallel to the magnetic field lines, because this is when the change in magnetic flux is greatest per unit time as the coil moves through different angles of exposure to the field. <br/>  <br/> Mathematically: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Induced</td><td style=\"text-align:center;\">e.m.f.</td><td style=\"text-align:center;\">ε</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-N</td><td style=\"text-align:center;\">dΦ<hr size=\"1\" />dt</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-N</td><td style=\"text-align:center;\">d(BAcosθ)<hr size=\"1\" />dt</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">NBAω</td><td style=\"text-align:center;\">sinθ</td></tr></table></div> <br/> This is maximum when sinθ = 1 (θ = 90°), which occurs when the coil is parallel to the field.</div>", "topic": "ELECTROMAGNETIC INDUCTION : A.C. AND D.C GENERATORS"}, {"id": "objective>Physics>2025 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which statement about the Earth's magnetic poles is TRUE?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The magnetic north pole is a north magnetic pole in physical terms.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The magnetic poles are fixed and do not move.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The magnetic south pole is near the geographic north pole.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Earth's magnetism comes from permanent magnets in the mantle.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statement is The magnetic south pole is near the geographic north pole, because in physics the \"north-seeking\" end of a compass needle points toward the Earth's geographic north, which is actually a magnetic south pole by definition, since opposite magnetic poles attract, and this magnetic south pole is not fixed but slowly drifts due to changes in the Earth's molten outer core that generates the geomagnetic field through the geodynamo effect.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>2025 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which statement correctly describes the difference between soft and hard X-rays?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Soft X-rays have longer wavelengths and lower energies, while hard X-rays have shorter wavelengths and higher energies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soft X-rays have shorter wavelengths and higher energies, while hard X-rays have longer wavelengths and lower energies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both have the same wavelength but differ in intensity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hard X-rays are only produced by synchrotron sources</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soft and hard X-rays differ mainly in wavelength and energy. <br/> Soft X-rays: Wavelength range roughly 0.1-10 nm, lower photon energies (~0.1-10 keV). They are easily absorbed by matter and are used for surface studies or biological imaging. <br/> Hard X-rays: Wavelength range roughly 0.01-0.1 nm, higher photon energies (~10-100 keV). They penetrate matter more effectively and are used in medical radiography and industrial inspection. <br/> The distinction comes from the inverse relationship between energy (E) and wavelength (λ) given by the photon energy formula: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">hc<hr size=\"1\" />λ</td></tr></table></div> <br/> where h is Planck's constant and c is the speed of light.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2025 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a moving iron instrument, hysteresis error can be minimized by:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Using hard steel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using soft iron with low retentivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using a laminated iron core</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Operating at low frequencies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a moving iron instrument, the deflection is caused by the magnetic field produced by the current flowing through its coil, which magnetizes a soft iron vane. If the iron retains some magnetism after the field is removed (high retentivity), it causes hysteresis error, making readings inaccurate—especially when current changes direction or magnitude. <br/> To minimize this error, soft iron with low retentivity is used so that it demagnetizes quickly when the current changes, ensuring accurate readings.</div>", "topic": "MAGNETIC FIELD : MOVING COIL AND MOVING IRON INSTRUMENTS"}, {"id": "objective>Physics>2025 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which light source operates primarily based on stimulated emission of radiation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">LED</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fluorescent lamp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Laser</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Incandescent bulb</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A laser (Light Amplification by Stimulated Emission of Radiation) produces light when excited atoms or molecules release photons in a process called stimulated emission. This results in light that is coherent, monochromatic, and highly directional. LEDs and incandescent bulbs rely on spontaneous emission, while fluorescent lamps use gas discharge and phosphor coating, not stimulated emission.</div>", "topic": "LIGHT ENERGY : SOURCE OF LIGHT"}, {"id": "objective>Physics>2025 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which principle explains why a pressure cooker reduces cooking time?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increased pressure lowers boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increased pressure raises boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduced pressure increases vapor pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduced pressure lowers melting point</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a pressure cooker, the pressure inside is higher than atmospheric pressure. According to the relationship between pressure and boiling point, increasing the external pressure on a liquid raises its boiling point. This means water in a pressure cooker can reach temperatures above 100°C before boiling, allowing food to cook faster because the higher temperature speeds up chemical reactions that cause food to soften and cook.</div>", "topic": "CHANGE OF STATE : EFFECT OF PRESSURE AND IMPURITIES ON BOILING AND MELTING POINTS"}, {"id": "objective>Physics>2025 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment, a student measures a physical quantity multiple times and finds that the results are all very close to each other, but they are consistently far from the known true value. The measurements can be described as:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High accuracy, but low precision.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low precision and low accuracy.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High precision and high accuracy.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High precision, but low accuracy.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Precision refers to how close repeated measurements are to each other. If the student's results are all very close together, precision is high. <br/>  <br/> Accuracy refers to how close a measurement is to the true or accepted value. If the results are far from the true value, accuracy is low. <br/>  <br/> In this case, the student is consistently wrong (low accuracy) but consistent in the error (high precision). <br/>  <br/> It's like hitting the same wrong spot on a dartboard every time — good grouping, but far from the bullseye.</div>", "topic": "MEASUREMENTS AND UNITS : LIMITATIONS OF EXPERIMENTAL MEASUREMENTS"}, {"id": "objective>Physics>2025 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which device does NOT obey Ohm's Law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Copper wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silicon diode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon resistor</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ohm's Law states that the current through a conductor is directly proportional to the potential difference across it, provided the temperature and other physical conditions remain constant. This means the V–I graph should be a straight line through the origin. <br/>  <br/> Ohmic devices: Copper wire, silver, carbon resistors — they follow Ohm's Law under constant temperature. <br/>  <br/> Non-ohmic devices: Tungsten filament (resistance changes significantly with temperature) and silicon diode (current only flows significantly in one direction, and the V–I graph is nonlinear). <br/>  <br/> Among the given options, the silicon diode clearly does not obey Ohm's Law under any normal operating conditions.</div>", "topic": "CURRENT ELECTRICITY: OHM'S LAW"}, {"id": "objective>Physics>2025 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A resistor network is shown in the figure. What is the equivalent resistance between points A and B? <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18.6 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.2 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.4 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0 Ω</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> are in series: <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6-7</span> = R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6-7</span> = 1 + 5 = 6 Ω <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> are in parallel: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4-5</span> = 2 Ω <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4-5</span> are in series: <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5</span> = R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4-5</span> <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5</span> = 2 + 2 = 4 Ω <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5</span> and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6-7</span> are in parallel: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5-6-7</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6-7</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5-6-7</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5-6-7</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />12</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5-6-7</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />5</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5-6-7</span> = 2.4 Ω <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>, R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3-4-5-6-7</span> are in series: <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1-2-3-4-5-6-7</span> = R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + (3-4-5-6-7) <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1-2-3-4-5-6-7</span> = 4 + 8 + 2.4 <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1-2-3-4-5-6-7</span> = 14.4 Ω <br/>  <br/> Therefore, the equivalent resistance between points A and B is 14.4 Ω</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE"}, {"id": "objective>Physics>2025 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about the Bohr model of the atom is NOT correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The angular momentum of an electron is quantized.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The total energy of an electron in an orbit is negative.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The model accurately predicts the spectra of multi-electron atoms.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electrons can only exist in certain discrete orbits.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The incorrect statement is \"The model accurately predicts the spectra of multi-electron atoms\" because, although the Bohr model successfully explains the quantized angular momentum, negative total energy of bound electrons, and the existence of discrete orbits, it fails to accurately predict the spectra of multi-electron atoms due to its inability to account for electron–electron interactions and other quantum effects.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>2025 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a derived physical quantity that is a combination of only two fundamental SI quantities?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Power</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Velocity is a derived quantity obtained from only two fundamental SI quantities — length (m) and time (s), so its unit is m/s. <br/>  <br/> Density (kg/m³) involves mass and volume, so it uses two quantities but has only one fundamental quantity. <br/>  <br/> Force (kg·m/s²) involves mass, length, time — three quantities. <br/>  <br/> Power (kg·m²/s³) also involves three fundamental quantities. <br/>  <br/> Velocity is the only one here that is purely from two fundamental quantities.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2025 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The visible lines of the hydrogen spectrum belong to the:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lyman series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paschen series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balmer series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brackett series</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrogen spectrum consists of several series of spectral lines, each corresponding to electron transitions between specific energy levels in the hydrogen atom: <br/>  <br/> Lyman series: Transitions to n = 1 (ultraviolet region) <br/>  <br/> Balmer series: Transitions to n = 2 (visible region) <br/>  <br/> Paschen series: Transitions to n = 3 (infrared region) <br/>  <br/> Brackett series: Transitions to n = 4 (infrared region) <br/>  <br/> In the Balmer series, electrons fall from higher energy levels (n ≥ 3) down to n = 2, producing wavelengths that lie in the visible spectrum. This is why the lines we see in laboratory hydrogen discharge tubes are in the Balmer series. <br/> </div>", "topic": "ELEMENTARY MODERN PHYSICS : ENERGY LEVELS AND SPECTRA"}, {"id": "objective>Physics>2025 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main cause of energy loss in power transmission is:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Magnetic leakage in transformers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Resistive heating of wires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dielectric loss in insulators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation of electromagnetic waves</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In power transmission, the major energy loss occurs due to resistive heating (also called I²R loss) in the conductors. When current flows through transmission lines, the resistance of the wires causes some of the electrical energy to be converted into heat, proportional to the square of the current (I²) and the resistance (R). While magnetic leakage, dielectric losses, and electromagnetic radiation losses do occur, they are comparatively minor in standard high-voltage transmission lines.</div>", "topic": "ELECTRICAL ENERGY AND POWER : ELECTRIC POWER TRANSMISSION"}, {"id": "objective>Physics>2025 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a saturated vapour is cooled at constant volume:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Its pressure remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its pressure decreases and condensation occurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its pressure increases due to molecular crowding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No change occurs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a saturated vapour at constant volume, the vapour is already at its maximum possible pressure for the given temperature (saturation pressure). When it is cooled, the temperature drops, lowering the saturation pressure. Since the vapour cannot remain at its previous higher pressure at the lower temperature, part of it condenses into liquid, thereby reducing the vapour pressure until it matches the new, lower saturation pressure corresponding to the reduced temperature. This is why both pressure decreases and condensation occurs.</div>", "topic": "VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2025 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two identical cells each of EMF 1.5 V and internal resistance 1 Ω are connected in parallel to supply current to a 2 Ω resistor. What is the total current?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4 A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1.5 V <br/> r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1 Ω <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1.5 V <br/> r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1 Ω <br/> R = 2 Ω <br/> I = ? <br/>  <br/> Since the cells are connected in parallel, <br/>  <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span> = E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1.5 V <br/>  <br/> Internal resistance in parallel: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td><td style=\"text-align:center;\">Ω</td></tr></table></div> <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span> = I(R + r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span>) <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span><hr size=\"1\" />R + r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />2 + 0.5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />2.5</td></tr></table></div> <br/> ∴ I = 0.6 A</div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>2025 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force between two parallel current-carrying wires is proportional to:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The product of currents and inversely proportional to distance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The sum of currents and inversely proportional to distance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The product of currents and directly proportional to distance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Independent of distance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For two long, straight, parallel conductors carrying currents I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>​ and I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>​, separated by a distance d, the force per unit length between them is given by: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<hr size=\"1\" />L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2πd</td></tr></table></div> <br/> where: <br/> μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> is the permeability of free space. <br/> The force is directly proportional to the product of the currents I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> × I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>​. <br/> The force is inversely proportional to the distance d between the wires. <br/>  <br/> If the currents are in the same direction, the wires attract; if in opposite directions, they repel.</div>", "topic": "MAGNETIC FIELD"}, {"id": "objective>Physics>2025 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A circular coil is pulled out of a region with a uniform magnetic field perpendicular to its plane. Which statement best describes the direction of the induced current?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It depends on the coil's material</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It flows to oppose the decrease in magnetic flux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It flows to aid the decrease in magnetic flux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is zero since the coil is leaving the field</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Lenz's Law, the induced current in a conductor flows in such a way that it opposes the change in magnetic flux that produced it. <br/>  <br/> Here: <br/>  <br/> - The coil is being pulled out of the magnetic field. <br/>  <br/> - The magnetic flux through the coil is therefore decreasing. <br/>  <br/> - To oppose this decrease, the induced current will produce its own magnetic field in the same direction as the original field, trying to keep the flux constant. <br/>  <br/> - Hence, the direction of induced current is such that it opposes the decrease in flux. <br/>  <br/> This is a perfect illustration of Lenz's Law: Nature resists change in magnetic flux.</div>", "topic": "ELECTROMAGNETIC INDUCTION : LENZ’S LAW"}, {"id": "objective>Physics>2025 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mercury barometer shows a column height of 760 mm at sea level. At the top of a mountain, the column height is 580 mm. What does this indicate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mercury density changed with altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gravity is stronger at the mountain top</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atmospheric pressure is lower at higher altitudes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mercury evaporates faster at higher altitudes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mercury barometer measures atmospheric pressure by balancing the weight of a mercury column against the atmospheric pressure pushing on the mercury reservoir. At sea level, the standard atmospheric pressure supports a 760 mm column of mercury. At the top of a mountain, air density and pressure are lower due to the reduced weight of the air above, so the barometer supports only a 580 mm column.</div>", "topic": "PRESSURE: ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2025 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The second overtone of a closed organ pipe has a frequency of 450 Hz. What is the length of the pipe if the speed of sound is 330 m/s?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">84.5 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">91.7 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">103.8 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">104.2 cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Second overtone frequency = 450 Hz <br/> Speed of sound = 330 m/s <br/>  <br/> For a closed organ pipe (closed at one end, open at the other), the harmonics are: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">nv<hr size=\"1\" />4L</td></tr></table></div> <br/> n = harmonic number (only odd integers: 1, 3, 5, 7, ...) <br/>  <br/> First harmonic (fundamental): n = 1 <br/>  <br/> First overtone: n = 3 <br/>  <br/> Second overtone: n = 5 <br/>  <br/> So, for the second overtone: n = 5. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">450</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5 × 330<hr size=\"1\" />4L</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">450</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1650<hr size=\"1\" />4L</td></tr></table></div> <br/> 1800L = 1650 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1650<hr size=\"1\" />1800</td></tr></table></div> <br/> ∴ L = 0.917 m = 91.7 cm</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : FREQUENCY OF A NOTE EMITTED BY AIR COLUMNS"}, {"id": "objective>Physics>2025 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The coefficient of viscosity (η) is defined by the equation F = ηA(<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">dv</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">dy</span>​), where F is the force, A is the area, and <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">dv</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">dy</span>​ is the velocity gradient. What is the fundamental SI unit of viscosity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N⋅s⋅m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">kg⋅m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span>⋅s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pa⋅s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The coefficient of viscosity η relates force F, area A, and velocity gradient <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">dv</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">dy</span>​ by: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ηAdv<hr size=\"1\" />dy</td></tr></table></div> ​  <br/> Rearranged: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">η</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />A</td><td style=\"text-align:center;\">⋅</td><td style=\"text-align:center;\">dy<hr size=\"1\" />dv</td><td style=\"text-align:center;\">​</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Force</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">has</td><td style=\"text-align:center;\">units:</td><td style=\"text-align:center;\">Newtons</td><td style=\"text-align:center;\">(N)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">kg⋅m<hr size=\"1\" />s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> Area A has units: m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Velocity</td><td style=\"text-align:center;\">gradient</td><td style=\"text-align:center;\">dv<hr size=\"1\" />dy</td><td style=\"text-align:center;\">​</td><td style=\"text-align:center;\">has</td><td style=\"text-align:center;\">units:</td><td style=\"text-align:center;\">s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span></td></tr></table></div> <br/> So: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">η</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">N<hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Pa⋅s</td></tr></table></div> <br/> Now, all options expressed in base units are equivalent: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">N⋅s⋅m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">kg ⋅ m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × s<hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">kg⋅m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span>⋅s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span></td></tr></table></div> <br/> - kg⋅m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span>⋅s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">Pa⋅s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">N<hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">⋅</td><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">kg⋅m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span>⋅s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span></td></tr></table></div> <br/> Therefore, all three are equivalent expressions of the SI unit of viscosity.</div>", "topic": "MEASUREMENTS AND UNITS : DERIVED PHYSICAL QUANTITIES AND THEIR UNITS"}, {"id": "objective>Physics>2025 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The work function of a metal is a fundamental property that affects thermionic emission. What does a low work function imply about a metal's suitability as a cathode material?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is easier for electrons to escape the surface, making it an excellent cathode material.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The kinetic energy of the emitted electrons is always higher.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is more difficult for electrons to escape the surface, so it is a poor cathode material.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A higher temperature is required to produce a given thermionic current.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work function is the minimum energy required for electrons to escape from the metal surface. A low work function means electrons need less energy to leave the metal, which makes the metal better suited as a cathode for thermionic emission because it can emit electrons more easily and efficiently at lower temperatures.</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC EMISSIONS"}];
